<?php
namespace App\Livewire\Billing;
use App\Models\Invoice; use Illuminate\Support\Facades\Gate; use Livewire\Component; use Livewire\WithPagination;
class Queue extends Component { use WithPagination; public string $tab='awaiting'; public string $search=''; public function mount(): void { Gate::authorize('billing.view-queue'); } public function render(){ return view('livewire.billing.queue',['invoices'=>Invoice::query()->forCurrentFacility()->with(['patient','visit','patientPayerProfile'])->when($this->tab==='awaiting',fn($q)=>$q->where('balance_amount','>',0))->when($this->tab==='partial',fn($q)=>$q->where('payment_status','partial'))->when($this->tab==='paid_today',fn($q)=>$q->where('payment_status','paid')->whereDate('updated_at',today()))->when($this->search,fn($q)=>$q->where('invoice_number','like','%'.$this->search.'%')->orWhereHas('patient',fn($p)=>$p->where('first_name','like','%'.$this->search.'%')->orWhere('last_name','like','%'.$this->search.'%')))->latest()->paginate(12)])->layout('components.layouts.app',['title'=>'Billing Queue','description'=>'Foleni ya wagonjwa wanaohitaji malipo au clearance.']); } }
